{
  "name": "EduStream - Smart Material Recommender",
  "description": "An AI-powered academic resource recommendation system that categorizes course materials and provides intelligent suggestions based on topics and learning objectives."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum MaterialCategory {
  VIDEO = 'Video',
  ARTICLE = 'Article',
  BOOK = 'Book',
  PODCAST = 'Podcast',
  COURSE = 'Course'
}

export interface Material {
  id: string;
  title: string;
  author: string;
  category: MaterialCategory;
  url: string;
  description: string;
  relevanceScore: number;
  tags: string[];
}

export interface RecommendationRequest {
  courseTitle: string;
  topic: string;
  level: 'Beginner' | 'Intermediate' | 'Advanced';
}

export interface AIRecommendationResponse {
  recommendations: Material[];
  summary: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { AIRecommendationResponse, RecommendationRequest } from "../types";

const API_KEY = process.env.API_KEY || '';

export const getAIRecommendations = async (req: RecommendationRequest): Promise<AIRecommendationResponse> => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const prompt = `Act as an expert academic advisor. Recommend exactly 4 high-quality educational materials for the following request:
  Course: ${req.courseTitle}
  Topic: ${req.topic}
  Difficulty Level: ${req.level}

  Provide a brief summary of why these materials are selected for this specific combination.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          summary: { 
            type: Type.STRING,
            description: "A summary of the recommendation strategy."
          },
          recommendations: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                title: { type: Type.STRING },
                author: { type: Type.STRING },
                category: { 
                    type: Type.STRING, 
                    enum: ['Video', 'Article', 'Book', 'Podcast', 'Course'] 
                },
                url: { type: Type.STRING },
                description: { type: Type.STRING },
                relevanceScore: { type: Type.NUMBER },
                tags: { 
                    type: Type.ARRAY,
                    items: { type: Type.STRING }
                }
              },
              required: ["id", "title", "author", "category", "description", "relevanceScore", "tags"]
            }
          }
        },
        required: ["summary", "recommendations"]
      }
    }
  });

  const result = JSON.parse(response.text || '{}');
  return result as AIRecommendationResponse;
};

