    e.preventDefault();
    if (!form.courseTitle || !form.topic) return;

    setLoading(true);
    try {
      const data = await getAIRecommendations(form);
      setResults(data);
      // Auto-add to history/library for demo purposes
      setLibrary(prev => [...data.recommendations, ...prev].slice(0, 20));
