    const categoryCounts = library.reduce((acc, item) => {
      acc[item.category] = (acc[item.category] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);

    const pieData = Object.entries(categoryCounts).map(([name, value]) => ({ name, value }));
