export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { AIRecommendationResponse, RecommendationRequest } from "../types";

export const getAIRecommendations = async (req: RecommendationRequest): Promise<AIRecommendationResponse> => {
  // Always use process.env.API_KEY directly and initialize right before use.
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Recommend exactly 4 high-quality educational materials for the following request:
  Course: ${req.courseTitle}
  Topic: ${req.topic}
  Difficulty Level: ${req.level}

  Provide a brief summary of why these materials are selected for this specific combination.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      // System instructions moved to config as per recommended practices.
      systemInstruction: "You are an expert academic advisor specializing in curating high-quality educational resources like videos, articles, books, podcasts, and courses.",
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          summary: { 
            type: Type.STRING,
            description: "A summary of the recommendation strategy."
          },
          recommendations: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                title: { type: Type.STRING },
                author: { type: Type.STRING },
                category: { 
                    type: Type.STRING, 
                    enum: ['Video', 'Article', 'Book', 'Podcast', 'Course'] 
                },
                url: { type: Type.STRING },
                description: { type: Type.STRING },
                relevanceScore: { type: Type.NUMBER },
                tags: { 
                    type: Type.ARRAY,
                    items: { type: Type.STRING }
                }
              },
              required: ["id", "title", "author", "category", "description", "relevanceScore", "tags"]
            }
          }
        },
        required: ["summary", "recommendations"]
      }
    }
  });

  // Accessing response.text as a property, not a method.
  const text = response.text;
  if (!text) {
    throw new Error("No response received from the AI service.");
  }

  try {
    return JSON.parse(text) as AIRecommendationResponse;
  } catch (error) {
    console.error("AI Response Parsing Error:", text);
    throw new Error("Received an invalid response format from the AI.");
  }
};

import React, { useState, useMemo } from 'react';
import { 
  Search, 
  Library, 
  BarChart3, 
  GraduationCap, 
  ChevronRight, 
  BookOpen, 
  ExternalLink, 
  Sparkles, 
  Filter,
  Loader2,
  TrendingUp,
  Award,
  BookMarked
} from 'lucide-react';
import { RecommendationRequest, Material, MaterialCategory } from './types';
import { getAIRecommendations } from './services/gemini';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  PieChart, 
  Pie, 
  Cell 
} from 'recharts';

const COLORS = ['#6366f1', '#8b5cf6', '#ec4899', '#f43f5e', '#f97316'];

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'recommend' | 'library' | 'analytics'>('recommend');
  const [loading, setLoading] = useState(false);
  const [form, setForm] = useState<RecommendationRequest>({
    courseTitle: '',
    topic: '',
    level: 'Beginner'
  });
  const [results, setResults] = useState<{ summary: string; recommendations: Material[] } | null>(null);

  // Initialize with some mock data for better first impression
  const [library, setLibrary] = useState<Material[]>([
    { 
      id: 'init-1', 
      title: 'Introduction to Algorithms', 
      author: 'Thomas H. Cormen', 
      category: MaterialCategory.BOOK, 
      url: 'https://mitpress.mit.edu/9780262046305/introduction-to-algorithms/', 
      description: 'A comprehensive guide to algorithm design and analysis.', 
      relevanceScore: 98, 
      tags: ['Computer Science', 'Algorithms'] 
    },
    { 
      id: 'init-2', 
      title: 'CS50: Introduction to Computer Science', 
      author: 'David J. Malan', 
      category: MaterialCategory.COURSE, 
      url: 'https://www.edx.org/course/introduction-computer-science-harvardx-cs50x', 
      description: 'Harvard University\'s introduction to the intellectual enterprises of computer science.', 
      relevanceScore: 95, 
      tags: ['CS50', 'Programming'] 
    }
  ]);

  const handleRecommend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.courseTitle || !form.topic) return;

    setLoading(true);
    try {
      const data = await getAIRecommendations(form);
      setResults(data);
      // Update library with new unique recommendations
      setLibrary(prev => {
        const existingIds = new Set(prev.map(p => p.id));
        const newOnes = data.recommendations.filter(r => !existingIds.has(r.id));
        return [...newOnes, ...prev];
      });
    } catch (error) {
