import React, { useState, useMemo } from 'react';
import { 
  Search, 
  Library, 
  BarChart3, 
  GraduationCap, 
  ChevronRight, 
  BookOpen, 
  ExternalLink, 
  Sparkles, 
  Filter,
  Loader2,
  TrendingUp,
  Award,
  BookMarked,
  Menu,
  X,
  User,
  Mail,
  Target,
  Lock,
  Eye,
  EyeOff,
  LogOut,
  ChevronLeft
} from 'lucide-react';
import { RecommendationRequest, Material, MaterialCategory } from './types';
import { getAIRecommendations } from './services/gemini';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  PieChart, 
  Pie, 
  Cell 
} from 'recharts';

const COLORS = ['#6366f1', '#8b5cf6', '#ec4899', '#f43f5e', '#f97316'];

interface UserProfile {
  username: string;
  email: string;
  password?: string;
  goal?: string;
}

const App: React.FC = () => {
  // Authentication State
  const [user, setUser] = useState<UserProfile | null>(null);
  const [authMode, setAuthMode] = useState<'login' | 'signup'>('signup');
  const [showPassword, setShowPassword] = useState(false);
  const [registrationForm, setRegistrationForm] = useState<UserProfile & { confirmPassword?: string }>({ 
    username: '', 
    email: '', 
    password: '',
    confirmPassword: '',
    goal: '' 
  });
  const [authError, setAuthError] = useState<string | null>(null);

  // Application State
  const [activeTab, setActiveTab] = useState<'recommend' | 'library' | 'analytics'>('recommend');
  const [loading, setLoading] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  const [form, setForm] = useState<RecommendationRequest>({
    courseTitle: '',
    topic: '',
    level: 'Beginner'
  });
  const [results, setResults] = useState<{ summary: string; recommendations: Material[] } | null>(null);

  const [library, setLibrary] = useState<Material[]>([
    { 
      id: 'init-1', 
      title: 'Introduction to Algorithms', 
      author: 'Thomas H. Cormen', 
      category: MaterialCategory.BOOK, 
      url: 'https://mitpress.mit.edu/9780262046305/introduction-to-algorithms/', 
      description: 'A comprehensive guide to algorithm design and analysis.', 
      relevanceScore: 98, 
      tags: ['Computer Science', 'Algorithms'] 
    },
    { 
      id: 'init-2', 
      title: 'CS50: Introduction to Computer Science', 
      author: 'David J. Malan', 
      category: MaterialCategory.COURSE, 
      url: 'https://www.edx.org/course/introduction-computer-science-harvardx-cs50x', 
      description: 'Harvard University\'s introduction to the intellectual enterprises of computer science.', 
      relevanceScore: 95, 
      tags: ['CS50', 'Programming'] 
    }
  ]);

  const validateEmail = (email: string) => {
    return email.toLowerCase().endsWith('@gmail.com');
  };

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    setAuthError(null);

    if (authMode === 'signup') {
      if (!registrationForm.username || !registrationForm.email || !registrationForm.password) {
        setAuthError("Please fill in all required fields.");
        return;
      }
      if (!validateEmail(registrationForm.email)) {
        setAuthError("Please use a valid Gmail address (@gmail.com).");
        return;
      }
      if (registrationForm.password.length < 6) {
        setAuthError("Password must be at least 6 characters.");
        return;
      }
      // Successful "Registration"
      setUser({
        username: registrationForm.username,
        email: registrationForm.email,
        goal: registrationForm.goal
      });
    } else {
      // Mock Login
      if (registrationForm.email && registrationForm.password) {
        setUser({
          username: registrationForm.username || registrationForm.email.split('@')[0],
          email: registrationForm.email
        });
      } else {
        setAuthError("Invalid credentials.");
      }
    }
  };

  const handleRecommend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.courseTitle || !form.topic) return;

    setLoading(true);
    try {
      const data = await getAIRecommendations(form);
      setResults(data);
      setLibrary(prev => {
        const existingIds = new Set(prev.map(p => p.id));
        const newOnes = data.recommendations.filter(r => !existingIds.has(r.id));
        return [...newOnes, ...prev];
      });
    } catch (error) {
      console.error("Failed to fetch recommendations:", error);
    } finally {
      setLoading(false);
    }
  };

  const analyticsData = useMemo(() => {
    const categoryCounts = library.reduce((acc, item) => {
      acc[item.category] = (acc[item.category] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);

    const pieData = Object.entries(categoryCounts).map(([name, value]) => ({ name, value }));
    const barData = library.slice(0, 6).map(item => ({
      name: item.title.length > 8 ? item.title.substring(0, 8) + '..' : item.title,
      score: item.relevanceScore
    }));

    return { pieData, barData };
  }, [library]);

  const MaterialCard: React.FC<{ material: Material }> = ({ material }) => (
