        <div className="p-4 sm:p-8 w-full max-w-6xl mx-auto flex-grow">
          {activeTab === 'recommend' && (
            <div className="space-y-6 sm:space-y-10 animate-in fade-in slide-in-from-bottom-2 duration-500">
              <section className="bg-white rounded-2xl sm:rounded-3xl border border-slate-200 p-6 sm:p-10 shadow-sm relative overflow-hidden">
                <div className="max-w-3xl relative z-10">
                  <h1 className="text-2xl sm:text-4xl font-extrabold text-slate-900 mb-2 sm:mb-4 tracking-tight leading-tight">
                    Hello, {user.username}. <br/><span className="text-indigo-600">Let's find your materials.</span>
                  </h1>
                  <p className="text-slate-500 text-sm sm:text-lg mb-6 sm:mb-8 leading-relaxed">Our AI analyzes your course requirements to find high-impact resources.</p>

                  <form onSubmit={handleRecommend} className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 sm:gap-6">
                    <div className="space-y-1.5">
                      <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Course Title</label>
                      <input 
                        type="text" 
                        placeholder="e.g. Psychology 101"
                        className="w-full px-4 py-2.5 sm:py-3 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:bg-white transition-all text-sm"
                        value={form.courseTitle}
                        onChange={(e) => setForm({...form, courseTitle: e.target.value})}
                        required
                      />
                    </div>
                    <div className="space-y-1.5">
                      <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Current Topic</label>
                      <input 
                        type="text" 
                        placeholder="e.g. Cognitive Bias"
                        className="w-full px-4 py-2.5 sm:py-3 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:bg-white transition-all text-sm"
                        value={form.topic}
                        onChange={(e) => setForm({...form, topic: e.target.value})}
                        required
                      />
                    </div>
                    <div className="space-y-1.5">
                      <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Depth Level</label>
                      <select 
                        className="w-full px-4 py-2.5 sm:py-3 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm cursor-pointer"
                        value={form.level}
                        onChange={(e) => setForm({...form, level: e.target.value as any})}
                      >
                        <option>Beginner</option>
                        <option>Intermediate</option>
                        <option>Advanced</option>
                      </select>
                    </div>
                    <div className="md:col-span-2 lg:col-span-3 flex justify-end pt-2 sm:pt-4">
                      <button 
                        type="submit"
                        disabled={loading}
                        className="w-full sm:w-auto bg-indigo-600 hover:bg-indigo-700 text-white px-8 py-3.5 rounded-xl sm:rounded-2xl font-bold text-sm shadow-xl shadow-indigo-200 transition-all flex items-center justify-center gap-3 disabled:opacity-70 active:scale-95"
                      >
                        {loading ? (
                          <>
                            <Loader2 className="animate-spin" size={18} /> Researching...
                          </>
                        ) : (
                          <>
                            Generate Recommendations <ChevronRight size={18} />
                          </>
                        )}
                      </button>
                    </div>
                  </form>
                </div>
                <div className="absolute right-0 top-0 h-full w-1/3 bg-indigo-50/50 clip-path-slant hidden lg:block"></div>
              </section>

              {results && (
                <div className="animate-in fade-in slide-in-from-bottom-8 duration-700 delay-150">
                  <div className="flex items-center gap-3 mb-6 sm:mb-8">
                    <div className="w-8 h-8 sm:w-10 sm:h-10 rounded-xl bg-amber-100 flex items-center justify-center text-amber-600 shadow-sm">
                      <Award size={20} />
                    </div>
                    <h2 className="text-xl sm:text-2xl font-bold text-slate-800">Curated for You</h2>
                  </div>

                  <div className="bg-indigo-50/50 border border-indigo-100 p-4 sm:p-6 rounded-2xl mb-8 sm:mb-10 flex gap-4 backdrop-blur-sm">
                    <div className="hidden sm:flex w-12 h-12 rounded-full bg-indigo-100 items-center justify-center shrink-0">
                       <Sparkles className="text-indigo-600" size={24} />
                    </div>
                    <div>
                      <p className="text-[10px] font-bold text-indigo-400 uppercase tracking-widest mb-1">AI Logic</p>
                      <p className="text-sm sm:text-base text-indigo-900 leading-relaxed font-semibold italic">"{results.summary}"</p>
                    </div>
                  </div>

                  <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 sm:gap-6">
                    {results.recommendations.map(m => (
                      <MaterialCard key={m.id} material={m} />
                    ))}
                  </div>
                </div>
              )}
            </div>
          )}

          {activeTab === 'library' && (
            <div className="space-y-6 animate-in fade-in duration-500">
              <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-4">
                <div>
                  <h1 className="text-2xl sm:text-3xl font-extrabold text-slate-900 tracking-tight">Resource Repository</h1>
                  <p className="text-xs sm:text-sm text-slate-500 mt-1">Your curated academic history.</p>
                </div>
                <button className="flex items-center justify-center gap-2 px-4 py-2 bg-white border border-slate-200 rounded-xl text-xs font-bold text-slate-600 hover:bg-slate-50 transition-all shadow-sm">
                  <Filter size={16} /> Filter Results
                </button>
              </div>

              {library.length > 0 ? (
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 sm:gap-6">
                  {library.map((m, idx) => (
                    <MaterialCard key={`${m.id}-${idx}`} material={m} />
                  ))}
                </div>
              ) : (
                <div className="flex flex-col items-center justify-center py-16 sm:py-24 bg-white rounded-3xl border-2 border-dashed border-slate-200">
                  <div className="w-16 h-16 sm:w-20 sm:h-20 bg-slate-50 rounded-full flex items-center justify-center text-slate-300 mb-6">
                    <BookMarked size={32} />
                  </div>
                  <h3 className="text-lg sm:text-xl font-bold text-slate-800 mb-2 text-center">Library Empty</h3>
                  <p className="text-slate-500 text-xs sm:text-sm max-w-xs text-center mb-8 leading-relaxed">Start discovering materials to build your collection.</p>
                  <button 
                    onClick={() => setActiveTab('recommend')}
                    className="bg-slate-900 text-white px-6 py-2.5 rounded-xl font-bold text-sm hover:bg-slate-800 transition-all"
                  >
                    Go to Discovery
                  </button>
                </div>
              )}
            </div>
          )}

          {activeTab === 'analytics' && (
            <div className="space-y-6 sm:space-y-10 animate-in fade-in duration-500">
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 sm:gap-6">
                <div className="bg-white p-5 sm:p-8 rounded-2xl sm:rounded-3xl border border-slate-200 shadow-sm">
                  <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-2 sm:mb-3">Resources Saved</p>
                  <div className="flex items-end justify-between">
                    <span className="text-2xl sm:text-4xl font-extrabold text-slate-800">{library.length}</span>
                    <span className="text-[10px] font-bold text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded-lg border border-emerald-100 flex items-center gap-1 shrink-0">
                      <TrendingUp size={10} /> +15%
                    </span>
                  </div>
                </div>
                <div className="bg-white p-5 sm:p-8 rounded-2xl sm:rounded-3xl border border-slate-200 shadow-sm">
                  <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-2 sm:mb-3">Avg Relevance</p>
                  <div className="flex items-end justify-between">
                    <span className="text-2xl sm:text-4xl font-extrabold text-slate-800">
                      {library.length > 0 
                        ? (library.reduce((a, b) => a + b.relevanceScore, 0) / library.length).toFixed(1) 
                        : '0'}%
                    </span>
                    <span className="text-[10px] font-bold text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded-lg border border-indigo-100 shrink-0">
                      Target Met
                    </span>
                  </div>
                </div>
                <div className="bg-white p-5 sm:p-8 rounded-2xl sm:rounded-3xl border border-slate-200 shadow-sm">
                  <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-2 sm:mb-3">Tool Rating</p>
                  <div className="flex items-end justify-between">
                    <span className="text-2xl sm:text-4xl font-extrabold text-slate-800 truncate">
                      {userRating ? `${userRating}/5` : 'N/A'}
                    </span>
                    <span className={`text-[10px] font-bold ${userRating ? 'text-amber-500 bg-amber-50 border-amber-100' : 'text-slate-400 bg-slate-50 border-slate-100'} px-2 py-0.5 rounded-lg border shrink-0`}>
                      {userRating ? 'Rating' : 'Pending'}
                    </span>
                  </div>
                </div>
                <div className="bg-white p-5 sm:p-8 rounded-2xl sm:rounded-3xl border border-slate-200 shadow-sm">
                  <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-2 sm:mb-3">Tier</p>
                  <div className="flex items-end justify-between">
                    <span className="text-2xl sm:text-4xl font-extrabold text-slate-800 truncate">Elite</span>
                    <span className="hidden sm:inline-block text-[10px] font-bold text-slate-500 bg-slate-50 px-2 py-0.5 rounded-lg border border-slate-100">
                      Active
                    </span>
                  </div>
                </div>
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 sm:gap-10">
                <div className="bg-white p-6 sm:p-10 rounded-2xl sm:rounded-3xl border border-slate-200 shadow-sm">
                  <h3 className="text-lg font-bold text-slate-900 mb-6 sm:mb-8 flex items-center gap-3">
                    <div className="w-8 h-8 rounded-lg bg-indigo-50 flex items-center justify-center text-indigo-600 shrink-0">
                      <BookOpen size={18} />
                    </div>
                    Material Mix
                  </h3>
                  <div className="h-48 sm:h-72 w-full">
                    {library.length > 0 ? (
                      <ResponsiveContainer width="100%" height="100%">
                        <PieChart>
                          <Pie
                            data={analyticsData.pieData}
                            cx="50%"
                            cy="50%"
                            innerRadius={50}
                            outerRadius={75}
                            paddingAngle={8}
                            dataKey="value"
                            stroke="none"
                          >
                            {analyticsData.pieData.map((entry, index) => (
                              <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                            ))}
                          </Pie>
                          <Tooltip 
                            contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)', fontSize: '10px' }} 
                          />
                        </PieChart>
                      </ResponsiveContainer>
                    ) : (
                      <div className="h-full flex items-center justify-center text-slate-300 italic text-xs">Analytics unavailable</div>
                    )}
                  </div>
                </div>

                <div className="bg-white p-6 sm:p-10 rounded-2xl sm:rounded-3xl border border-slate-200 shadow-sm">
                  <h3 className="text-lg font-bold text-slate-900 mb-6 sm:mb-8 flex items-center gap-3">
                    <div className="w-8 h-8 rounded-lg bg-emerald-50 flex items-center justify-center text-emerald-600 shrink-0">
                      <TrendingUp size={18} />
                    </div>
                    Top Scores
                  </h3>
                  <div className="h-48 sm:h-72 w-full">
                    {library.length > 0 ? (
                      <ResponsiveContainer width="100%" height="100%">
                        <BarChart data={analyticsData.barData}>
                          <CartesianGrid strokeDasharray="4 4" vertical={false} stroke="#f1f5f9" />
                          <XAxis 
                            dataKey="name" 
                            axisLine={false} 
                            tickLine={false} 
                            tick={{fontSize: 9, fill: '#94a3b8', fontWeight: 600}} 
                          />
                          <YAxis 
                            domain={[0, 100]} 
                            axisLine={false} 
                            tickLine={false} 
                            tick={{fontSize: 9, fill: '#94a3b8'}} 
                          />
                          <Tooltip 
                            cursor={{fill: '#f8fafc'}} 
                            contentStyle={{ borderRadius: '10px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)', fontSize: '10px' }}
                          />
                          <Bar dataKey="score" fill="#6366f1" radius={[6, 6, 0, 0]} barSize={24} />
                        </BarChart>
                      </ResponsiveContainer>
                    ) : (
                      <div className="h-full flex items-center justify-center text-slate-300 italic text-xs">Analytics unavailable</div>
                    )}
                  </div>
                </div>
              </div>

              {/* Tool Feedback/Testimonial Section in Analytics */}
              <div className="bg-gradient-to-br from-indigo-600 to-purple-700 p-8 sm:p-12 rounded-3xl text-white shadow-xl relative overflow-hidden">
                <Sparkles className="absolute -right-6 -top-6 opacity-10" size={160} />
                <div className="max-w-xl relative z-10">
                  <div className="flex items-center gap-3 mb-6">
                    <div className="w-12 h-12 bg-white/20 backdrop-blur-md rounded-2xl flex items-center justify-center">
                      <MessageSquare size={24} />
                    </div>
                    <h3 className="text-2xl font-bold">Your opinion matters</h3>
                  </div>
                  <p className="text-indigo-100 text-lg mb-8 leading-relaxed">
                    EduStream is constantly learning from your interactions. Help us improve the discovery engine by sharing your experience.
                  </p>
                  <div className="flex flex-col sm:flex-row gap-4">
                    <button 
                      onClick={() => alert("Detailed feedback form coming soon!")}
                      className="bg-white text-indigo-600 px-8 py-3 rounded-xl font-bold text-sm hover:bg-indigo-50 transition-all flex items-center justify-center gap-2"
                    >
                      Write a Review <ExternalLink size={16} />
                    </button>
                    {!feedbackSubmitted && (
                      <div className="flex items-center gap-1 bg-white/10 backdrop-blur-md px-4 py-2 rounded-xl">
                        {[1, 2, 3, 4, 5].map(s => (
                          <Star key={s} size={20} className="text-white/40" />
                        ))}
                        <span className="text-[10px] font-bold uppercase ml-2 opacity-60 tracking-widest">Rate in sidebar</span>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;
